// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra.evaluation.util;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.evaluation.ValueExprEvaluationException;
import org.eclipse.rdf4j.query.algebra.evaluation.function.Function;
import org.eclipse.rdf4j.query.algebra.evaluation.function.FunctionRegistry;
import org.eclipse.rdf4j.query.algebra.evaluation.function.datetime.Now;
import org.junit.jupiter.api.Test;

/**
 * Probes every registered function that the optimizer treats as repeatable by evaluating it twice with the same sample
 * arguments and requiring equal results (or a consistently thrown evaluation error). This probe can detect some false
 * determinism declarations; <strong>passing does not establish determinism</strong> — a stateful or clock-dependent
 * function can return identical results for every probe. It is CI tooling for the whitelist and for third-party
 * {@link Function.Determinism#DETERMINISTIC} declarations, never an input to the optimizer.
 */
public class DeterministicFunctionProbeTest {

	private static final ValueFactory vf = SimpleValueFactory.getInstance();

	private static List<Value[]> sampleArguments() {
		List<Value[]> samples = new ArrayList<>();
		samples.add(new Value[] {});
		samples.add(new Value[] { vf.createLiteral("abc") });
		samples.add(new Value[] { vf.createLiteral(1) });
		samples.add(new Value[] { vf.createLiteral("2026-01-01T12:30:15.5+02:00",
				org.eclipse.rdf4j.model.vocabulary.XSD.DATETIME) });
		samples.add(new Value[] { vf.createIRI("http://example.com/x") });
		samples.add(new Value[] { vf.createLiteral("abc"), vf.createLiteral("b") });
		samples.add(new Value[] { vf.createLiteral("abc"), vf.createLiteral("1"), vf.createLiteral("2") });
		samples.add(new Value[] { vf.createLiteral("abc"), vf.createIRI("http://example.com/dt") });
		return samples;
	}

	@Test
	public void repeatableFunctionsProbeConsistently() {
		int probed = 0;
		for (Function function : FunctionRegistry.getInstance().getAll()) {
			if (!QueryEvaluationUtility.isRepeatable(function) || function instanceof Now) {
				continue;
			}
			boolean produced = false;
			for (Value[] args : sampleArguments()) {
				Value first;
				try {
					first = function.evaluate(vf, args);
				} catch (ValueExprEvaluationException | IllegalArgumentException e) {
					continue;
				}
				Value second = function.evaluate(vf, args);
				assertEquals(first, second,
						"function " + function.getURI() + " treated as repeatable returned differing results");
				produced = true;
			}
			if (produced) {
				probed++;
			}
		}
		assertTrue(probed >= 25, "probe degraded: only " + probed + " repeatable functions produced values");
	}

	@Test
	public void freshnessFunctionsAreNotRepeatable() {
		for (Function function : FunctionRegistry.getInstance().getAll()) {
			if (function.mustReturnDifferentResult()) {
				assertFalse(QueryEvaluationUtility.isRepeatable(function),
						"must-differ function " + function.getURI() + " may never be treated as repeatable");
				assertFalse(QueryEvaluationUtility.isSafeForPlanConstantFolding(function));
			}
		}
	}

	@Test
	public void nowIsQueryStableButNeverPlanFolded() {
		Now now = new Now();
		assertTrue(QueryEvaluationUtility.isRepeatable(now));
		assertFalse(QueryEvaluationUtility.isSafeForPlanConstantFolding(now));
	}
}
